head.script:
//전역변수
scwin.g_sCurrDate       = WebSquare.date.getCurrentServerDate();
scwin.crn               = ""
scwin.busiNm            = ""

scwin.onpageload = function() {

};


scwin.onUdcCompleted = function() {
    if (scwin.crn != "" && scwin.crn.length > 0){
        ed_crn.setValue(scwin.crn);
        ed_crnNm.setValue(scwin.busiNm);
        scwin.f_Retrieve();
    }
    scwin.f_getFinalCloseYearMonth();
}

//-------------------------------------------------------------------------
// 마감년월구하기
//-------------------------------------------------------------------------
scwin.f_getFinalCloseYearMonth = function () {

    // SELECT 절 
    let param1 =  "DECODE(MIN(CLOSE_YM),SUBSTR(TO_CHAR(SYSDATE,'YYYYMMDD'),1,6), TO_CHAR(SYSDATE,'YYYYMMDD') , TO_CHAR(LAST_DAY(TO_DATE(MIN(CLOSE_YM),'YYYYMM')),'YYYYMMDD')) as COL1"
                + ",''	 	as COL2 "
                + ",'' 		as COL3 "
                + ",'' 		as COL4 "
                + ",'' 		as COL5 "
                + ",'' 		as COL6 "
                + ",''      as COL7 "
                + ",''      as COL8 "
                + ",''      as COL9 "
                + ",''      as COL10"
                ;

    // 대상테이블 	
    let param2 =  " TB_ZZ419 " ;

    // 조건절
    let param3 =  " AND WRK_NO = 'FI01'"
                + " AND CLOSE_PRGS_STS_CD ='1'"
                + " AND CO_CD ='000'" 
                ;
    // 정렬    
    let param4 = 	
            " COL1 "
        ;

    sbm_getFinalCloseYM.action =  "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest"	+ "&param1=" + param1 
                                                                                                    + "&param2=" + param2
                                                                                                    + "&param3=" + param3 
                                                                                                    + "&param4=" + param4;	                                                    
    $c.sbm.execute(sbm_getFinalCloseYM)
}

