//-------------------------------------------------------------------------
// 엑셀저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = async function(e) {
    if (ds_crdtLimitRemainAmtMgnt.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let fileName = '여신한도잔액';

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_crdtLimitRemainAmtMgnt, { fileName: fileName + ".xlsx", sheetName: fileName });
    }
};

